/**
 * n8n Code node (drop-in)
 * Adds dedupe_key generation for inbound_receipts upsert.
 *
 * Dedupe strategy:
 *  - Prefer message-id + pod_id (best for (pod_id, dedupe_key) uniqueness)
 *  - Fallback to message-id + to_localpart
 *  - Last resort: hash-like fallback using subject_hash/payload_hash/timestamp
 *
 * Also preserves existing content_date extraction logic.
 */

function normalizeSpaces(s) {
  return String(s || "")
    .replace(/[\u00A0\u202F\u2007]/g, " ")
    .replace(/[\u200B-\u200D\uFEFF]/g, "")
    .replace(/\r\n/g, "\n");
}

function extractEmail(s) {
  if (!s) return null;
  const str = String(s);
  const angle = str.match(/<([^>]+)>/);
  if (angle?.[1]) return angle[1].trim().toLowerCase();
  const simple = str.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return simple ? simple[0].trim().toLowerCase() : null;
}

function monthToIndex(mon) {
  const m = String(mon || "").toLowerCase();
  const map = {
    jan: 0, january: 0,
    feb: 1, february: 1,
    mar: 2, march: 2,
    apr: 3, april: 3,
    may: 4,
    jun: 5, june: 5,
    jul: 6, july: 6,
    aug: 7, august: 7,
    sep: 8, sept: 8, september: 8,
    oct: 9, october: 9,
    nov: 10, november: 10,
    dec: 11, december: 11,
  };
  return map[m] ?? null;
}

function pad2(n) {
  return String(n).padStart(2, "0");
}

function parseToYMD(dateStr) {
  if (!dateStr) return null;
  const s = normalizeSpaces(dateStr).trim();

  const d1 = new Date(s);
  if (!Number.isNaN(d1.getTime()) && /[+-]\d{4}\b/.test(s)) {
    return d1.toISOString().slice(0, 10);
  }

  let m = s.match(/\b([A-Za-z]{3,9})\s+(\d{1,2}),\s*(\d{4})\b/);
  if (m) {
    const monIdx = monthToIndex(m[1]);
    const day = parseInt(m[2], 10);
    const year = parseInt(m[3], 10);
    if (monIdx !== null && year >= 1900 && day >= 1 && day <= 31) {
      return `${year}-${pad2(monIdx + 1)}-${pad2(day)}`;
    }
  }

  m = s.match(/\b(\d{1,2})\s+([A-Za-z]{3,9})\s+(\d{4})\b/);
  if (m) {
    const day = parseInt(m[1], 10);
    const monIdx = monthToIndex(m[2]);
    const year = parseInt(m[3], 10);
    if (monIdx !== null && year >= 1900 && day >= 1 && day <= 31) {
      return `${year}-${pad2(monIdx + 1)}-${pad2(day)}`;
    }
  }

  const d2 = new Date(s);
  if (!Number.isNaN(d2.getTime())) {
    return d2.toISOString().slice(0, 10);
  }

  return null;
}

function extractForwardedBlocks(text) {
  const t = normalizeSpaces(text);
  const lines = t.split("\n");
  const blocks = [];

  for (let i = 0; i < lines.length; i++) {
    const line = (lines[i] || "").trim();
    const isFwd =
      /forwarded message/i.test(line) ||
      /begin forwarded message/i.test(line);

    if (!isFwd) continue;

    let from = null;
    let date = null;

    for (let j = i; j < Math.min(i + 25, lines.length); j++) {
      const l = (lines[j] || "").trim();

      if (!from) {
        const fm = l.match(/^From:\s*(.+)\s*$/i);
        if (fm?.[1]) from = fm[1].trim();
      }
      if (!date) {
        const dm = l.match(/^Date:\s*(.+)\s*$/i);
        if (dm?.[1]) date = dm[1].trim();
      }

      if (from && date) {
        blocks.push({ from, date, index: i });
        break;
      }
    }
  }

  return blocks;
}

function pickContentDate(body) {
  const senderEmail =
    extractEmail(body?.sender) ||
    extractEmail(body?.["X-Envelope-From"]) ||
    extractEmail(body?.from);

  const textCandidates = [
    body?.["stripped-text"],
    body?.["body-plain"],
    body?.["stripped-html"],
    body?.["body-html"],
  ].filter(Boolean);

  let blocks = [];
  for (const txt of textCandidates) {
    const b = extractForwardedBlocks(txt);
    if (b.length) blocks = blocks.concat(b);
  }

  if (blocks.length) {
    const scored = blocks.map((b, idx) => {
      const fromEmail = extractEmail(b.from);
      const fromDiffers = senderEmail && fromEmail && fromEmail !== senderEmail;
      return { ...b, fromEmail, fromDiffers, idx };
    });

    const vendorBlocks = scored.filter(x => x.fromDiffers);
    const chosenList = vendorBlocks.length ? vendorBlocks : scored;
    const chosen = chosenList[chosenList.length - 1];

    const ymd = parseToYMD(chosen.date);
    if (ymd) return { ymd, source: "forwarded_header", raw: chosen.date, from: chosen.fromEmail || chosen.from };
  }

  const outer = body?.Date || body?.date;
  const outerYmd = parseToYMD(outer);
  if (outerYmd) return { ymd: outerYmd, source: "outer_header", raw: outer };

  return { ymd: null, source: "none", raw: null };
}

// ------------------- dedupe helpers -------------------

function getToLocalpart(itemJson) {
  const explicit = itemJson?.to_localpart;
  if (explicit) return String(explicit).trim().toLowerCase();

  const toEmail = itemJson?.to_email || itemJson?.to;
  const email = extractEmail(toEmail) || (toEmail ? String(toEmail).trim().toLowerCase() : null);
  if (email && email.includes("@")) return email.split("@")[0];

  return null;
}

function getMessageId(itemJson) {
  // Prefer normalized field if already present
  const direct = itemJson?.message_id;
  if (direct) return String(direct).trim();

  // Try common Mailgun/raw fields
  const candidates = [
    itemJson?.body?.["Message-Id"],
    itemJson?.body?.["message-id"],
    itemJson?.body?.["message_id"],
    itemJson?.body?.["Message-ID"],
    itemJson?.body?.["X-Message-Id"],
    itemJson?.["Message-Id"],
    itemJson?.["message-id"],
  ].filter(Boolean);

  const found = candidates.find(Boolean);
  return found ? String(found).trim() : null;
}

function buildDedupeKey({ channel, podId, toLocalpart, messageId, subjectHash, payloadHash }) {
  const ch = channel || "mailgun";
  const scope = podId || toLocalpart || "unknown";
  if (messageId) return `${ch}:${scope}:${messageId}`;

  // last resort: stable-ish fallback
  const fallback = payloadHash || subjectHash || String(Date.now());
  return `${ch}:${scope}:fallback:${fallback}`;
}

// ---- n8n entrypoint ----
return $input.all().map((item) => {
  const body = item.json?.body ?? {};
  const { ymd, source, raw, from } = pickContentDate(body);

  const channel = item.json?.channel || "mailgun";
  const podId = item.json?.pod_id ? String(item.json.pod_id) : null;

  const toLocalpart = getToLocalpart(item.json);
  const messageId = getMessageId(item.json);

  const dedupeKey = buildDedupeKey({
    channel,
    podId,
    toLocalpart,
    messageId,
    subjectHash: item.json?.subject_hash,
    payloadHash: item.json?.payload_hash,
  });

  return {
    json: {
      ...item.json,

      // keep/augment normalized fields
      channel,
      to_localpart: toLocalpart ?? item.json?.to_localpart ?? null,
      message_id: messageId ?? item.json?.message_id ?? null,
      dedupe_key: dedupeKey,

      // your content_date fields
      content_date: ymd,
      content_date_source: source,
      content_date_raw: raw,
      content_date_from: from ?? null,
    },
  };
});

