/**
 * n8n Code node: Verify Mailgun Signature (outputs isValid)
 *
 * - Does NOT throw on invalid signature (so IF node can route)
 * - DOES throw if MAILGUN_SIGNING_KEY is missing (config error)
 */

const crypto = require('crypto');

const MAILGUN_SIGNING_KEY = $vars.MAILGUN_SIGNING_KEY;

if (!MAILGUN_SIGNING_KEY) {
  throw new Error('MAILGUN_SIGNING_KEY is not set');
}

function getBody(json) {
  if (json.body && typeof json.body === 'object') return json.body;
  return json;
}

const original = $json;
const body = getBody(original);

const timestamp = body.timestamp;
const token = body.token;
const signature = body.signature;

let isValid = false;
let error = null;

if (!timestamp || !token || !signature) {
  error = 'missing_signature_fields';
} else {
  const data = `${timestamp}${token}`;
  const expectedSignature = crypto
    .createHmac('sha256', MAILGUN_SIGNING_KEY)
    .update(data)
    .digest('hex');

  isValid =
    signature.length === expectedSignature.length &&
    crypto.timingSafeEqual(
      Buffer.from(signature, 'utf8'),
      Buffer.from(expectedSignature, 'utf8')
    );

  if (!isValid) error = 'invalid_signature';
}

// Attach verification result, pass everything through
return [{
  json: {
    ...original,
    signature_check: {
      isValid,
      error,
      // optional debug fields if you want:
      // hasTimestamp: !!timestamp,
      // hasToken: !!token,
      // hasSignature: !!signature,
    },
  }
}];

// receipt_id from the inbound_receipts upsert result
const receipt_id = $('Acknowledge Receipt').first().json?.id ?? null;

// This Code node runs after FetchPod (serial wiring), so current $json is the pod row (or empty)
const pod_id = $json?.id ?? null;

return [
  {
    json: {
      receipt_id,
      pod_id,
    },
  },
];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();
